// NODO: Operator_Merger
// VERSIONE: 2.5 - Allineamento chat_id esclusivamente in user_ref per gli operatori

for (const item of $input.all()) {

  // ━━━ 1. ALLINEAMENTO CHAT_ID UTENTE OPERATORE ━━━
  if (item.json.body && item.json.body.operator_data && item.json.body.operator_data.data) {
    const opProfile = item.json.body.operator_data.data;

    if (opProfile.user_ref) {
      // Estrae il chat_id personale dell'operatore
      const opChatId = opProfile.user_ref.chat_id || 
                       opProfile.user_ref.operator_chat_id || 
                       item.json.body.chat_id || 
                       null;

      if (opChatId) {
        // Scrive la chiave standard "chat_id" unificata SOLO in user_ref
        opProfile.user_ref.chat_id = opChatId;
      }
    }
    // owner_data_ref non viene toccato per preservare il chat_id dell'Owner di riferimento
  }

  // ━━━ 2. AGGIORNAMENTO OPERATORI SULL'OWNER (Logica Originale) ━━━
  const operators = item.json.owner_data.operators || [];
  const updateData = item.json.body.owner_operators_update;

  if (updateData) {
    item.json.owner_data.operators = operators.map(operator => {
      if (operator.OperatorChatID === updateData.OperatorChatID) {
        const updatedOperator = {
          ...operator,
          ...updateData
        };
        delete updatedOperator.invitation_code;
        return updatedOperator;
      }
      return operator;
    });
  }
}

return $input.all();

