// ═══════════════════════════════════════════════════════════════
const item = $input.first().json;
const original = $node["PrepareRequest"].json;
const owner = item.owner_data || {}; 

const baseUrl = original.UrlMiniApp;
const chatId = original.Operator_request.message.chat.id;
const userMsgId = original.Operator_request.message.message_id;
const messageIdToEdit = userMsgId - 1; 

const credits = owner.credits_balance || 0;

// --- LOGICA ASH ---
function generateSignature(str, key) {
    let hash = 0; const combined = str + key;
    for (let i = 0; i < combined.length; i++) {
        hash = ((hash << 5) - hash) + combined.charCodeAt(i);
        hash = hash & hash; 
    }
    return Math.abs(hash).toString(16);
}

const SECRET_KEY = 'TrinAI-Autorize-Transaction-2=2&';
const ts = Date.now().toString();
const webhookId = "ef4aece4-9ec0-4026-a7a7-328562bcbdf6"; 
const ownerId = owner.chat_id || owner.user_id;

const payloadASH = `${ownerId}|${chatId}|${ts}|${webhookId}`;
const ash = `${Buffer.from(payloadASH).toString('base64')}.${generateSignature(payloadASH, SECRET_KEY)}`;

const t = {
    header: `⚙️ <b>SiteBoS Operator KeyBoard</b>`,
    entity: `🏢 <b>${(owner.ragione_sociale || 'PRIVATE_TENANT').toUpperCase()}</b>`,
    user: `👤 OPERATORE: <b>${owner.name || ''} ${owner.surname || ''}</b>`,
    status: `📊 OPERATIVITÀ: <b>IN SERVIZIO</b>`,
    balance: `🔋 RESIDUO AZIONI: <b>${credits}</b>`,
    gdpr: `🔐 <b>PROTOCOLLO SICUREZZA</b>\n<i>I dati operativi sono cifrati e trattati secondo il GDPR.</i>`
};

const buttons = [
    [{ text: "📋 Missioni & Task Attivi", web_app: { url: `${baseUrl}operators/operator_tasks.html?ash=${ash}&msg_id=${messageIdToEdit}` } }],
    [{ text: "🧠 Analisi e Percorso Personale", web_app: { url: `${baseUrl}softskill/index.html?ash=${ash}&msg_id=${messageIdToEdit}` } }],
    [
        { text: "📦 Ordini", web_app: { url: `${baseUrl}orders-manager.html?ash=${ash}&msg_id=${messageIdToEdit}` } },
        { text: "📝 Preventivi", web_app: { url: `${baseUrl}preventivi.html?ash=${ash}&msg_id=${messageIdToEdit}` } }
    ],
    [
        { text: "🤝 Supporto Hub", web_app: { url: `${baseUrl}support_hub.html?ash=${ash}&msg_id=${messageIdToEdit}` } },
        { text: "🛠️ Magazzino", web_app: { url: `${baseUrl}new-insert.html?ash=${ash}&msg_id=${messageIdToEdit}` } }
    ],
    [
        { text: "🛡️ SuperVisor", web_app: { url: `${baseUrl}operators/catalog.html?ash=${ash}&msg_id=${messageIdToEdit}` } }, 
        { text: "📊 Performance", callback_data: "op_stats" }
    ],
    [
        { text: "🔄 Sincronizza Sistema", callback_data: "open_agent_control_center" }
    ]
];

return [{
    json: {
